+using System.Text.RegularExpressions;
+
+namespace DocSummary.Services;
+
+/// <summary>
+/// Extractive summarizer that scores sentences by word frequency
+/// and returns the top-ranked ones in their original order.
+/// </summary>
+public partial class ExtractiveSummarizer : IDocumentSummarizer
+{
+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
+        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
+        "this", "that", "be", "as", "has", "have", "had", "do", "does",
+        "not", "so", "if", "its", "can", "will", "just", "he", "she",
+        "we", "they", "i", "you", "my", "his", "her", "our", "their"
+    };
+
+    public string Summarize(string documentText, int maxSentences)
+    {
+        var sentences = SplitSentences(documentText);
+
+        if (sentences.Count <= maxSentences)
+            return string.Join(" ", sentences);
+
+        var wordFrequencies = ComputeWordFrequencies(sentences);
+        var scored = ScoreSentences(sentences, wordFrequencies);
+
+        var topIndices = scored
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .Select(s => s.Index)
+            .OrderBy(i => i);
+
+        return string.Join(" ", topIndices.Select(i => sentences[i]));
+    }
+
+    private static List<string> SplitSentences(string text)
+    {
+        return SentenceRegex()
+            .Split(text)
+            .Select(s => s.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in WordRegex().Matches(sentence).Select(m => m.Value))
+            {
+                if (StopWords.Contains(word) || word.Length < 2)
+                    continue;
+
+                if (!freq.TryAdd(word, 1))
+                    freq[word]++;
+            }
+        }
+
+        return freq;
+    }
+
+    private static List<(int Index, double Score)> ScoreSentences(
+        List<string> sentences, Dictionary<string, int> wordFrequencies)
+    {
+        var maxFreq = wordFrequencies.Values.DefaultIfEmpty(1).Max();
+
+        return sentences.Select((sentence, index) =>
+        {
+            var words = WordRegex().Matches(sentence).Select(m => m.Value).ToList();
+            if (words.Count == 0)
+                return (index, Score: 0.0);
+
+            var score = words.Sum(w =>
+                wordFrequencies.TryGetValue(w, out var f) ? (double)f / maxFreq : 0);
+
+            return (index, Score: score / words.Count);
+        }).ToList();
+    }
+
+    [GeneratedRegex(@"(?<=[.!?])\s+")]
+    private static partial Regex SentenceRegex();
+
+    [GeneratedRegex(@"\b\w+\b")]
+    private static partial Regex WordRegex();
